arguments.argument:
if other.damageType="SHOT" and other.y>=y+20
{
  if other.direction=0
  {
    if x<xstart+128
    {
      if xVel>1 {xVel=3.5}
      else if xVel<0 {xVel=0.5}
      else {xVel=2}
    }
  }
  else if other.direction=180
  {
    if x>xstart-128
    {
      if xVel<-1 {xVel=-3.5}
      else if xVel>0 {xVel=-0.5}
      else {xVel=-2}
    }
  }
}
